; 愚者の倉庫

name = 愚者の倉庫４
insideName = Floor 4
level = 23
bgm = trick
external = w:1
shadow = dark
sky = black
roof = stone
blank = rock
antiWarp = true

; 各パーツ
━ = stone
　 = marble
❖ = marble
☆ = soilr
❑ = cube
⧻ = fence
☖ = arch
☗ = gate
︻ = panel

; 移動ポイント
(A) = map:愚者の倉庫３, x:10, y:3, way:w, symbol:exit, ask:Go to the previous floor?
(B) = map:愚者の倉庫５, x:4, y:10, way:s, symbol:exit, ask:Go to the next floor?

; 宝箱
box[1] = 罠はない,ミラーウォールの魔法書_u,強力眠気ざまし,経験のコイン（小）

[map]
