[correct]

[endmap]
;-------------------------------------------------------------------------------
; マップを開いた時に必ず実行されるスクリプト
[initial]

switchFence(6, 1, "n", events.has(1) ? "close" : "open");
switchFence(8, 0, "w", events.has(1) ? "close" : "open");

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3]

;-------------------------------------------------------------------------------
*event_1
;[exp] party.lastIsPush

@eventoff cond='game.map.getFloorInfo(11, 3).type != "movable"'
@eventoff cond='game.map.getFloorInfo(11, 2).type != "movable"'
@eventoff cond='game.map.getFloorInfo(11, 1).type != "movable"'
@eventoff cond='game.map.getFloorInfo(11, 0).type != "movable"'
@eventoff cond='game.map.getFloorInfo(12, 3).type != "movable"'
@eventoff cond='game.map.getFloorInfo(12, 2).type != "movable"'
@eventoff cond='game.map.getFloorInfo(12, 1).type != "movable"'
@eventoff cond='game.map.getFloorInfo(12, 0).type != "movable"'
@delevent
@wait time=1000
@se f=fence
@switchfence x=6 y=1 way=n mode=open
@switchfence x=8 y=0 way=w mode=open
@notice text="I heard a door open somewhere!"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@notice text="It would be better to put off clearing away the rocks on the left side."

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@notice text="Think twice before placing a stone at<r>N:2 E:11 or N:0 E:11"

[eventoff]
;-------------------------------------------------------------------------------
*reset_floor

[if exp='! game.map.events.has(1)']
	@call storage="anime.ks" target=*failed_to_reset
	[eventoff]
[endif]

@se f=dragstone
@eval exp='game.map.reset()'
@wait time=800
@warp x=0 y=0 way=e
@notice text="All the stones on the floor have returned to their original positions. You were warped back to near the entrance!"

[eventoff]
;-------------------------------------------------------------------------------
